import './main.scss'
import {
  updateData
} from './js/utils'
import quickedit from './js/quickedit'
import {
  editPageStatus,
  normalPagesStatus
} from './js/pagestatus'

(function($) {

  const $body = $('body')
  let $pagesStatus
  let formClass

  const waitPageslist = setInterval(() => {

    if(poeticsoft_heart_campus_admin_pageslist) {

      clearInterval(waitPageslist)
      
      if($body.hasClass('block-editor-page')) {

        formClass = 'EditPage'
        $pagesStatus = editPageStatus($)
      }

      if($body.hasClass('edit-php')) {

        formClass = 'PagesList'
        $pagesStatus = normalPagesStatus($)
      }
      
      if(
        $pagesStatus
        &&
        $pagesStatus.length
      ) {
        
        window.poeticsoft_heart_campus_admin_pageslist_updatedata = () => {

          updateData($, $pagesStatus, formClass)
        }

        window.poeticsoft_heart_campus_admin_pageslist_updatedata();
      }

      quickedit($)
    }

  }, 100)

})(jQuery)

