export const rowForm = (
  $, 
  postId, 
  elm = 'div',
  data = {}
) => {

  return `<${ elm } id="${ postId }" class="PHCAccess">
    <div class="AccessTools">
      <div class="PostId">${ postId.replace('post-', '') }</div>
      <div class="Access">${ data.isopen ? 'Abierta' : 'Restringida' }</div>
    </div>
  </${ elm }>`
}