const { apiFetch } = wp

export const getPageStatus = (pageId) => {

  return apiFetch({
    path: `poeticsoft/heart/campus/v1/page/access/get/${pageId}`,
    method: "GET"
  })
  .catch(error => console.error('Heart Campus API Error:', error));
}

export const updateData = ($, $pageStatuses) => {

  return apiFetch({
    path: 'poeticsoft/heart/campus/v1/page/access/get',
    method: "GET"
  })
  .then(response => {

    const pages = response.data.pages


    $pageStatuses.each(function() {

      const $this = $(this);
      const id = $this.attr('id').replace('post-', '');
      const $access = $this.find('.AccessTools .Access');

      if (pages[id] === 'abierta') {
        $access.addClass('isOpen');
        $access.html('Abierta');
      } else {
        $access.removeClass('isOpen');
        $access.html('Restringida');
      }
    });
  })
  .catch(error => console.error('Heart Campus API Error:', error));
}